/**
 * Lists users using FW/1 rc/prc boundaries.
 *
 * @rc Request collection.
 * @prc Private request collection.
 * @return void
 */
public void function list(required struct rc, required struct prc) {
  var status = structKeyExists(arguments.rc, 'status') ? arguments.rc.status : 'active';
  arguments.prc.users = variables.userService.getUsersByStatus(status);
  arguments.prc.status = status;
}

