/**
 * Normalizes paging input before action execution.
 *
 * @rc Request collection.
 * @prc Private request collection.
 * @return void
 */
public void function before(required struct rc, required struct prc) {
  var requestedPage = val(structKeyExists(arguments.rc, 'page') ? arguments.rc.page : 1);
  arguments.rc.page = requestedPage > 0 ? requestedPage : 1;
}

/**
 * Handles uncaught FW/1 exceptions for user-safe output.
 *
 * @exception Exception structure from FW/1.
 * @event Event metadata.
 * @rc Request collection.
 * @prc Private request collection.
 * @return void
 */
public void function onError(required struct exception, required string event, required struct rc, required struct prc) {
  variables.logger.error('Unhandled FW/1 error', arguments.exception);
  arguments.prc.errorMessage = 'An unexpected error occurred. Please try again.';
}

