/**
 * Builds dashboard summary metrics.
 *
 * @accountId Account identifier.
 * @return struct
 */
public struct function getDashboardSummary(required numeric accountId) {
  var totals = variables.reportRepository.getTotals(arguments.accountId);
  return {
    activeUsers: totals.activeUsers,
    openTickets: totals.openTickets,
    renewalCount: totals.renewalCount
  };
}

/**
 * User service for account operations.
 */
component singleton accessors='false' {

  /**
   * Repository dependency injected by DI/1.
   */
  property name='userRepository' inject='UserRepository';

  /**
   * Reads a user profile.
   *
   * @userId User identifier.
   * @return struct
   */
  public struct function getProfile(required numeric userId) {
    return variables.userRepository.getProfile(arguments.userId);
  }
}

