/**
 * Configures FW/1 subsystems for module routing.
 *
 * @return struct
 */
public struct function configureSubsystems() {
  return {
    admin: {
      path: '/admin',
      defaultSection: 'dashboard'
    }
  };
}

/**
 * Handles profile form submission and redirects on success.
 *
 * @rc Request collection.
 * @prc Private request collection.
 * @return void
 */
public void function save(required struct rc, required struct prc) {
  if (!len(trim(arguments.rc.email ?: ''))) {
    arguments.prc.validationError = 'Email is required.';
    return;
  }

  variables.userService.saveProfile(arguments.rc);
  framework.redirect(action = 'profile.list');
}

/**
 * Lazily resolves optional exporter dependency for one-off use.
 *
 * @rc Request collection.
 * @prc Private request collection.
 * @return void
 */
public void function export(required struct rc, required struct prc) {
  var exporter = variables.beanFactory.getBean('ReportExporter');
  arguments.prc.filePath = exporter.generate(arguments.rc.reportId);
}
